from collections import deque

def coinChange(self, coins, amount):
    if amount == 0:
        return 0
    visited = set([0])
    queue = deque([0])
    steps = 0
    while queue:
        steps += 1
        for _ in range(len(queue)):
            curr = queue.popleft()
            for coin in coins:
                nxt = curr + coin
                if nxt == amount:
                    return steps
                if nxt < amount and nxt not in visited:
                    visited.add(nxt)
                    queue.append(nxt)
    return -1

