from functools import lru_cache

def coinChange(self, coins, amount):
    @lru_cache(maxsize=None)
    def dp(rem):
        if rem < 0:
            return float('inf')
        if rem == 0:
            return 0
        return min(dp(rem - c) + 1 for c in coins)

    result = dp(amount)
    return result if result != float('inf') else -1
